function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function applyBoxBlur(cellValues, numRows, numCols, strength) {
  var result = new Float32Array(cellValues);
  var passes = Math.floor(strength);

  for (var pass = 0; pass < passes; pass += 1) {
    var temp = new Float32Array(result.length);
    for (var row = 0; row < numRows; row += 1) {
      for (var col = 0; col < numCols; col += 1) {
        var sum = 0;
        var count = 0;
        for (var dy = -1; dy <= 1; dy += 1) {
          for (var dx = -1; dx <= 1; dx += 1) {
            var sampleRow = row + dy;
            var sampleCol = col + dx;
            if (sampleRow >= 0 && sampleRow < numRows && sampleCol >= 0 && sampleCol < numCols) {
              sum += result[sampleRow * numCols + sampleCol];
              count += 1;
            }
          }
        }
        temp[row * numCols + col] = sum / count;
      }
    }
    result = temp;
  }

  var fractional = strength - Math.floor(strength);
  if (fractional > 0) {
    for (var i = 0; i < result.length; i += 1) {
      result[i] = cellValues[i] * (1 - fractional) + result[i] * fractional;
    }
  }

  return result;
}

function applyFloydSteinbergDithering(cellValues, numRows, numCols) {
  var threshold = 128;
  for (var row = 0; row < numRows; row += 1) {
    for (var col = 0; col < numCols; col += 1) {
      var index = row * numCols + col;
      var oldValue = cellValues[index];
      var newValue = oldValue < threshold ? 0 : 255;
      var error = oldValue - newValue;
      cellValues[index] = newValue;
      if (col + 1 < numCols) {
        cellValues[row * numCols + (col + 1)] += error * (7 / 16);
      }
      if (row + 1 < numRows) {
        if (col - 1 >= 0) {
          cellValues[(row + 1) * numCols + (col - 1)] += error * (3 / 16);
        }
        cellValues[(row + 1) * numCols + col] += error * (5 / 16);
        if (col + 1 < numCols) {
          cellValues[(row + 1) * numCols + (col + 1)] += error * (1 / 16);
        }
      }
    }
  }
}

