function createMediaSource(type, src) {
  return new Promise(function(resolve, reject) {
    if (type === 'video') {
      var video = document.createElement('video');
      video.crossOrigin = 'anonymous';
      video.loop = true;
      video.muted = true;
      video.playsInline = true;
      video.setAttribute('webkit-playsinline', 'true');
      video.addEventListener('loadeddata', function() { resolve(video); }, { once: true });
      video.addEventListener('error', function() { reject(new Error('Failed to load video source.')); }, { once: true });
      video.src = src;
      video.load();
      return;
    }

    var image = new Image();
    image.crossOrigin = 'anonymous';
    image.addEventListener('load', function() { resolve(image); }, { once: true });
    image.addEventListener('error', function() { reject(new Error('Failed to load image source.')); }, { once: true });
    image.src = src;
  });
}

